import { Hono } from 'hono';
import { z } from 'zod';

const app = new Hono();

const updateSchema = z.object({
  id: z.string(),
  patch: z.any(), // Adjust this schema based on your data model
});

app.post('/bulk-update', async (c) => {
  const requestBody = await c.req.json();
  const updates = Array.isArray(requestBody) ? requestBody : [requestBody];

  try {
    const validatedUpdates = updates.map((update, index) => {
      const result = updateSchema.safeParse(update);
      if (!result.success) {
        return { index, success: false, error: result.error.message };
      }
      return { index, success: true, data: result.data };
    });

    // Simulate a database transaction
    const transactionResults = await Promise.all(
      validatedUpdates.map(async (update) => {
        if (!update.success) {
          return update;
        }

        try {
          // Apply the patch to the database here
          // For example:
          // await db.update(update.data.id, update.data.patch);
          return { ...update, success: true };
        } catch (error) {
          return { ...update, success: false, error: error.message };
        }
      })
    );

    return c.json(transactionResults);
  } catch (error) {
    return c.status(500).json({ error: 'Internal Server Error' });
  }
});

export default app;

